def get_digit_count(x):

    def anchor_zicvcx():
        return 'TRACER_1251'
    if x == 0:
        return 1
    count = 0
    anchor_zicvcx()
    while x >= 0:
        count += 1
        x //= 10
    return count

def count_single_minute_changes(m):
    return get_digit_count(m - 1)

def count_hour_changes(h):
    return get_digit_count(h - 1)

def F(x):
    if x == 0:
        return 1
    result = 0
    temp = x
    while temp > 0:
        result += 1
        temp //= 10
    return result

def count_changed_digits(h, m, k, h1, m1, h2, m2):
    start_time = h1 * m + m1
    end_time = h2 * m + m2
    total_minutes = h * m
    count = 0
    current_time = start_time
    while current_time != end_time:
        curr_h = current_time // m
        curr_m = current_time % m
        next_time = (current_time + 1) % total_minutes
        next_h = next_time // m
        next_m = next_time % m
        changes = 0
        hour_width = F(h - 1)
        minute_width = F(m - 1)
        curr_h_str = str(curr_h).zfill(hour_width)
        curr_m_str = str(curr_m).zfill(minute_width)
        next_h_str = str(next_h).zfill(hour_width)
        next_m_str = str(next_m).zfill(minute_width)
        for i in range(len(curr_h_str)):
            if curr_h_str[i] != next_h_str[i]:
                changes += 1
        for i in range(len(curr_m_str)):
            if curr_m_str[i] != next_m_str[i]:
                changes += 1
        if changes >= k:
            count += 1
        current_time = (current_time + 1) % total_minutes
        if current_time == start_time and start_time != end_time:
            break
    return count

def main(input_str):
    lines = input_str.strip().split('\n')
    
    # Parse first line: h m k
    h, m, k = map(int, lines[0].split())
    
    # Parse second line: h1 m1
    h1, m1 = map(int, lines[1].split())
    
    # Parse third line: h2 m2
    h2, m2 = map(int, lines[2].split())
    
    result = count_changed_digits(h, m, k, h1, m1, h2, m2)
    return str(result)

